def range_summary(nums):
    if not nums:
        return ''

    distinct_nums = sorted(set(nums))
    result = []
    start = end = distinct_nums[0]

    for num in distinct_nums[1:]:
        if num == end + 1:
            end = num
        else:
            if start == end:
                result.append(f'{start}')
            else:
                result.append(f'{start}-{end}')
            start = end = num

    if start == end:
        result.append(f'{start}')
    else:
        result.append(f'{start}-{end}')

    return ','.join(result)
